mapper.select:
SELECT e.exam_id, e.exam_name, e.paper_id, e.class_id, e.start_time, e.end_time, e.status, e.allow_screen_switch, e.create_by, e.create_time, p.paper_name, p.duration, c.class_name, (SELECT COUNT(*) FROM student WHERE class_id = e.class_id) as student_count, (SELECT COUNT(*) FROM exam_record WHERE exam_id = e.exam_id AND status = 2) as submitted_count FROM exam e LEFT JOIN exam_paper p ON e.paper_id = p.paper_id LEFT JOIN class c ON e.class_id = c.class_id WHERE e.create_time BETWEEN #{startTime} AND #{endTime}
AND e.create_by = #{createBy}
ORDER BY e.create_time DESC

SELECT e.exam_id, e.exam_name, e.paper_id, e.class_id, e.start_time, e.end_time, e.status, e.allow_screen_switch, e.create_by, e.create_time, p.paper_name, p.duration, c.class_name, (SELECT COUNT(*) FROM student WHERE class_id = e.class_id) as student_count, (SELECT COUNT(*) FROM exam_record WHERE exam_id = e.exam_id AND status = 2) as submitted_count FROM exam e LEFT JOIN exam_paper p ON e.paper_id = p.paper_id LEFT JOIN class c ON e.class_id = c.class_id
WHERE e.create_by = #{createBy}
ORDER BY e.create_time DESC LIMIT #{limit}
